SELECT e.experiment_id, e.description, t.tag
FROM experiments e
JOIN experiment_tags t ON e.experiment_id = t.experiment_id;

SELECT AVG(stoc_pol_mean)
FROM experiments
WHERE experiment_id BETWEEN 10 AND 20 AND status = 'completed';

SELECT hyperparameter_name, hyperparameter_value
FROM algorithm_hyperparameters
WHERE algorithm_id = 1;

SELECT environment_id, COUNT(experiment_id) AS experiment_count
FROM experiment_environment
GROUP BY environment_id;

SELECT algorithm_id, COUNT(*) as num_hyperparameters
FROM algorithm_hyperparameters
GROUP BY algorithm_id;

SELECT tag
FROM experiment_tags
WHERE experiment_id = 1;

SELECT * 
FROM experiments 
WHERE time_vpg > (SELECT AVG(time_vpg) FROM experiments);

SELECT algorithms.algorithm_name, algorithm_hyperparameters.hyperparameter_name, algorithm_hyperparameters.hyperparameter_value
FROM algorithms
JOIN algorithm_hyperparameters ON algorithms.algorithm_id = algorithm_hyperparameters.algorithm_id;

SELECT AVG(CAST(hyperparameter_value AS REAL)) AS mean_hyperparameter_value
FROM algorithm_hyperparameters
WHERE hyperparameter_name = 'your_specific_hyperparameter';
